SELECT COUNT(*) AS total_sales
FROM sales
WHERE size_id = (SELECT size_id FROM shirt_sizes WHERE size_label = 'X-Small');

SELECT total_sales
FROM size_popularity
WHERE size_id = 1;

SELECT size_label
FROM shirt_sizes
WHERE size_id = 1;

SELECT size_label, chest, waist
FROM shirt_sizes
ORDER BY size_id ASC;

SELECT shirt_type, size_system, COUNT(size_id) AS size_count
FROM shirt_sizes
GROUP BY shirt_type, size_system;

SELECT total_sales
FROM size_popularity
WHERE size_id = 1;
